import{_ as a,c as i,o,a1 as l}from"./chunks/framework.DILC4Csi.js";const c=JSON.parse('{"title":"Обзор плагина: возможности и риски | Antigravity Auth","description":"Изучите ключевые преимущества и предупреждения о рисках плагина Antigravity Auth. Доступ к моделям Claude и Gemini 3 через Google OAuth с поддержкой балансировки нагрузки между несколькими аккаунтами.","frontmatter":{"title":"Обзор плагина: возможности и риски | Antigravity Auth","sidebarTitle":"Подходит ли вам этот плагин","subtitle":"Узнайте ключевые преимущества плагина Antigravity Auth","description":"Изучите ключевые преимущества и предупреждения о рисках плагина Antigravity Auth. Доступ к моделям Claude и Gemini 3 через Google OAuth с поддержкой балансировки нагрузки между несколькими аккаунтами.","tags":["Начало работы","Обзор плагина","OpenCode","Antigravity"],"order":1},"headers":[],"relativePath":"ru/NoeFabris/opencode-antigravity-auth/start/what-is-antigravity-auth/index.md","filePath":"ru/NoeFabris/opencode-antigravity-auth/start/what-is-antigravity-auth/index.md"}'),e={name:"ru/NoeFabris/opencode-antigravity-auth/start/what-is-antigravity-auth/index.md"};function r(n,t,s,h,u,d){return o(),i("div",null,[...t[0]||(t[0]=[l('<h1 id="узнаите-ключевые-преимущества-плагина-antigravity-auth" tabindex="-1">Узнайте ключевые преимущества плагина Antigravity Auth <a class="header-anchor" href="#узнаите-ключевые-преимущества-плагина-antigravity-auth" aria-label="Permalink to &quot;Узнайте ключевые преимущества плагина Antigravity Auth&quot;">​</a></h1><p><strong>Antigravity Auth</strong> — это плагин для OpenCode, который обеспечивает доступ к Antigravity API через аутентификацию Google OAuth. Он позволяет использовать продвинутые модели, такие как Claude Opus 4.5, Sonnet 4.5 и Gemini 3 Pro/Flash, с помощью вашего привычного аккаунта Google — без необходимости управлять API-ключами. Плагин также предоставляет балансировку нагрузки между несколькими аккаунтами, двойной пул квот и автоматическое восстановление сессий — идеально для пользователей, которым нужны продвинутые модели и автоматизированное управление.</p><h2 id="чему-вы-научитесь" tabindex="-1">Чему вы научитесь <a class="header-anchor" href="#чему-вы-научитесь" aria-label="Permalink to &quot;Чему вы научитесь&quot;">​</a></h2><ul><li>Определить, подходит ли этот плагин для вашего сценария использования</li><li>Узнать, какие AI-модели и основные функции поддерживает плагин</li><li>Понять риски и меры предосторожности при использовании плагина</li><li>Принять решение о продолжении установки и настройки</li></ul><h2 id="ваша-текущая-проблема" tabindex="-1">Ваша текущая проблема <a class="header-anchor" href="#ваша-текущая-проблема" aria-label="Permalink to &quot;Ваша текущая проблема&quot;">​</a></h2><p>Вы хотите использовать самые передовые AI-модели (такие как Claude Opus 4.5, Gemini 3 Pro), но официальный доступ ограничен. Вы ищете надёжный способ получить доступ к этим моделям и при этом хотите:</p><ul><li>Не управлять вручную несколькими API-ключами</li><li>Автоматически переключаться на другой аккаунт при достижении лимита запросов</li><li>Автоматически восстанавливать диалог после прерывания без потери контекста</li></ul><h2 id="основная-идея" tabindex="-1">Основная идея <a class="header-anchor" href="#основная-идея" aria-label="Permalink to &quot;Основная идея&quot;">​</a></h2><p><strong>Antigravity Auth</strong> — это плагин для OpenCode, который обеспечивает доступ к Google Antigravity API через <strong>аутентификацию Google OAuth</strong>, позволяя вызывать продвинутые AI-модели с помощью вашего привычного аккаунта Google.</p><p>Он не проксирует все запросы, а <strong>перехватывает и преобразует</strong> ваши запросы к моделям, перенаправляя их в Antigravity API, а затем конвертирует ответы обратно в формат, понятный OpenCode.</p><h2 id="основные-возможности" tabindex="-1">Основные возможности <a class="header-anchor" href="#основные-возможности" aria-label="Permalink to &quot;Основные возможности&quot;">​</a></h2><h3 id="поддерживаемые-модели" tabindex="-1">Поддерживаемые модели <a class="header-anchor" href="#поддерживаемые-модели" aria-label="Permalink to &quot;Поддерживаемые модели&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Семейство моделей</th><th>Доступные модели</th><th>Особенности</th></tr></thead><tbody><tr><td><strong>Claude</strong></td><td>Opus 4.5, Sonnet 4.5</td><td>Поддержка режима расширенного мышления</td></tr><tr><td><strong>Gemini 3</strong></td><td>Pro, Flash</td><td>Интеграция с Google Search, расширенное мышление</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">Режим мышления (Thinking)</p><p>Модели с режимом Thinking выполняют «глубокое размышление» перед генерацией ответа, показывая процесс рассуждения. Вы можете настроить бюджет мышления для баланса между качеством и скоростью ответа.</p></div><h3 id="балансировка-нагрузки-между-несколькими-аккаунтами" tabindex="-1">Балансировка нагрузки между несколькими аккаунтами <a class="header-anchor" href="#балансировка-нагрузки-между-несколькими-аккаунтами" aria-label="Permalink to &quot;Балансировка нагрузки между несколькими аккаунтами&quot;">​</a></h3><ul><li><strong>Поддержка до 10 аккаунтов Google</strong></li><li>Автоматическое переключение на следующий аккаунт при достижении лимита запросов (ошибка 429)</li><li>Три стратегии выбора аккаунта: sticky (фиксированный), round-robin (ротация), hybrid (интеллектуальный гибрид)</li></ul><h3 id="система-двоиных-квот" tabindex="-1">Система двойных квот <a class="header-anchor" href="#система-двоиных-квот" aria-label="Permalink to &quot;Система двойных квот&quot;">​</a></h3><p>Плагин одновременно использует <strong>два независимых пула квот</strong>:</p><ol><li><strong>Квота Antigravity</strong>: от Google Antigravity API</li><li><strong>Квота Gemini CLI</strong>: от Google Gemini CLI</li></ol><p>Когда один пул достигает лимита, плагин автоматически пробует другой, максимизируя использование квот.</p><h3 id="автоматическое-восстановление-сессии" tabindex="-1">Автоматическое восстановление сессий <a class="header-anchor" href="#автоматическое-восстановление-сессии" aria-label="Permalink to &quot;Автоматическое восстановление сессий&quot;">​</a></h3><ul><li>Обнаружение неудачных вызовов инструментов (например, при нажатии ESC для прерывания)</li><li>Автоматическая инъекция синтетического tool_result для предотвращения сбоя диалога</li><li>Поддержка автоматической отправки &quot;continue&quot; для продолжения диалога</li></ul><h3 id="интеграция-с-google-search" tabindex="-1">Интеграция с Google Search <a class="header-anchor" href="#интеграция-с-google-search" aria-label="Permalink to &quot;Интеграция с Google Search&quot;">​</a></h3><p>Включение веб-поиска для моделей Gemini для повышения фактической точности:</p><ul><li><strong>Режим Auto</strong>: модель сама решает, нужен ли поиск</li><li><strong>Режим Always-on</strong>: поиск выполняется каждый раз</li></ul><h2 id="когда-использовать-этот-плагин" tabindex="-1">Когда использовать этот плагин <a class="header-anchor" href="#когда-использовать-этот-плагин" aria-label="Permalink to &quot;Когда использовать этот плагин&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Подходит для следующих сценариев</p><ul><li>У вас несколько аккаунтов Google и вы хотите увеличить общую квоту</li><li>Вам нужны модели Claude или Gemini 3 с режимом Thinking</li><li>Вы хотите включить Google Search для моделей Gemini</li><li>Вы не хотите вручную управлять API-ключами и предпочитаете OAuth-аутентификацию</li><li>Вы часто сталкиваетесь с лимитами запросов и хотите автоматическое переключение аккаунтов</li></ul></div><div class="warning custom-block"><p class="custom-block-title">Не подходит для следующих сценариев</p><ul><li>Вам нужны модели, которые Google официально не публикует</li><li>Вы очень чувствительны к рискам нарушения ToS Google (см. предупреждение о рисках ниже)</li><li>Вам нужны только базовые модели Gemini 1.5 или Claude 3 (официальные интерфейсы стабильнее)</li><li>Вам сложно открыть браузер в средах WSL, Docker и подобных</li></ul></div><h2 id="⚠️-важное-предупреждение-о-рисках" tabindex="-1">⚠️ Важное предупреждение о рисках <a class="header-anchor" href="#⚠️-важное-предупреждение-о-рисках" aria-label="Permalink to &quot;⚠️ Важное предупреждение о рисках&quot;">​</a></h2><p>Использование этого плагина <strong>может нарушать Условия использования Google</strong>. Небольшое количество пользователей сообщили, что их аккаунты Google были <strong>заблокированы</strong> или <strong>теневым образом ограничены</strong> (доступ ограничен без явного уведомления).</p><h3 id="сценарии-высокого-риска" tabindex="-1">Сценарии высокого риска <a class="header-anchor" href="#сценарии-высокого-риска" aria-label="Permalink to &quot;Сценарии высокого риска&quot;">​</a></h3><ul><li>🚨 <strong>Совершенно новые аккаунты Google</strong>: очень высокая вероятность блокировки</li><li>🚨 <strong>Аккаунты с недавно оформленной подпиской Pro/Ultra</strong>: легко помечаются и блокируются</li></ul><h3 id="перед-использованием-убедитесь" tabindex="-1">Перед использованием убедитесь <a class="header-anchor" href="#перед-использованием-убедитесь" aria-label="Permalink to &quot;Перед использованием убедитесь&quot;">​</a></h3><ul><li>Это <strong>неофициальный инструмент</strong>, не одобренный Google</li><li>Ваш аккаунт может быть временно или навсегда заблокирован</li><li>Вы принимаете на себя все риски использования этого плагина</li></ul><h3 id="рекомендации" tabindex="-1">Рекомендации <a class="header-anchor" href="#рекомендации" aria-label="Permalink to &quot;Рекомендации&quot;">​</a></h3><ul><li>Используйте <strong>зрелые аккаунты Google</strong>, а не создавайте новые специально для этого плагина</li><li>Избегайте использования важных аккаунтов, связанных с критическими сервисами</li><li>Если аккаунт заблокирован, обжаловать через этот плагин невозможно</li></ul><div class="danger custom-block"><p class="custom-block-title">Безопасность аккаунта</p><p>Все OAuth-токены хранятся локально в <code>~/.config/opencode/antigravity-accounts.json</code> и не загружаются ни на какие серверы. Однако убедитесь, что ваш компьютер защищён, чтобы предотвратить утечку токенов.</p></div><h2 id="итоги-урока" tabindex="-1">Итоги урока <a class="header-anchor" href="#итоги-урока" aria-label="Permalink to &quot;Итоги урока&quot;">​</a></h2><p>Antigravity Auth — это мощный плагин для OpenCode, который позволяет получить доступ к продвинутым моделям Claude и Gemini 3 через Google OAuth. Он предоставляет балансировку нагрузки между несколькими аккаунтами, двойной пул квот, автоматическое восстановление сессий и другие функции — идеально для пользователей, которым нужны продвинутые модели и автоматизированное управление.</p><p>Но обязательно учтите: <strong>использование этого плагина несёт риск блокировки аккаунта</strong>. Используйте некритичные аккаунты Google и ознакомьтесь с рисками перед продолжением установки.</p><h2 id="анонс-следующего-урока" tabindex="-1">Анонс следующего урока <a class="header-anchor" href="#анонс-следующего-урока" aria-label="Permalink to &quot;Анонс следующего урока&quot;">​</a></h2><blockquote><p>В следующем уроке мы изучим <strong><a href="./../quick-install/">Быструю установку</a></strong>.</p><p>Вы узнаете:</p><ul><li>Как установить плагин за 5 минут</li><li>Как добавить первый аккаунт Google</li><li>Как проверить успешность установки</li></ul></blockquote>',42)])])}const p=a(e,[["render",r]]);export{c as __pageData,p as default};
